<script setup lang="ts">
import {computed,onMounted,ref} from 'vue'
import {useRouter} from 'vue-router'
import {api} from '../api.ts'
type CountItem={label:string;count:number;status?:string;city?:string}
type TrendItem={date:string;label:string;count:number}
type RecentItem={id:number;name:string;phone:string;city?:string;district?:string;createdAt:string;unread:boolean}
type Overview={stats:{products:number;news:number;slides:number;bookings:number;todayBookings:number;weekBookings:number;newBookings:number};trend:TrendItem[];statuses:CountItem[];cities:CountItem[];recent:RecentItem[]}
const empty:Overview={stats:{products:0,news:0,slides:0,bookings:0,todayBookings:0,weekBookings:0,newBookings:0},trend:[],statuses:[],cities:[],recent:[]}
const data=ref<Overview>(empty);const loading=ref(true);const router=useRouter()
onMounted(async()=>{try{const response=(await api.get('/dashboard/overview')).data;if(response?.stats)data.value=response}catch(error:any){if(error?.response?.status===401)await router.push('/login')}finally{loading.value=false}})
const trendMax=computed(()=>Math.max(1,...data.value.trend.map(item=>item.count)))
const chartPoints=computed(()=>data.value.trend.map((item,index)=>`${35+index*88},${145-(item.count/trendMax.value)*105}`).join(' '))
const chartDots=computed(()=>data.value.trend.map((item,index)=>({x:35+index*88,y:145-(item.count/trendMax.value)*105,...item})))
const statusMax=computed(()=>Math.max(1,...data.value.statuses.map(item=>item.count)))
const cityMax=computed(()=>Math.max(1,...data.value.cities.map(item=>item.count)))
const formatDate=(value:string)=>new Date(value).toLocaleString('zh-CN',{month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',hour12:false})
</script>
<template><div v-loading="loading" class="dashboard">
  <div class="dashboard-title"><div><h1 class="page-title">数据概览</h1><p>预约业务和官网内容的实时状态</p></div><el-tag v-if="data.stats.newBookings" type="danger" effect="dark">{{data.stats.newBookings}} 条预约待联系</el-tag></div>
  <div class="kpi-grid">
    <RouterLink to="/bookings" class="kpi-card primary"><span>今日预约</span><strong>{{data.stats.todayBookings}}</strong><small>今天收到的试驾申请</small></RouterLink>
    <RouterLink to="/bookings" class="kpi-card"><span>本周预约</span><strong>{{data.stats.weekBookings}}</strong><small>本周一至今天</small></RouterLink>
    <RouterLink to="/bookings?status=NEW" class="kpi-card warning"><span>待联系</span><strong>{{data.stats.newBookings}}</strong><small>点击立即处理</small></RouterLink>
    <RouterLink to="/bookings" class="kpi-card"><span>全部预约</span><strong>{{data.stats.bookings}}</strong><small>累计客户线索</small></RouterLink>
  </div>
  <div class="dashboard-grid main-charts">
    <section class="data-panel trend-panel"><div class="panel-title"><div><h2>最近 7 天预约趋势</h2><p>每日新增试驾预约数量</p></div></div><div v-if="data.trend.length" class="trend-chart"><svg viewBox="0 0 600 180" preserveAspectRatio="none" aria-label="最近7天预约趋势"><line v-for="y in [40,75,110,145]" :key="y" x1="30" :y1="y" x2="570" :y2="y" class="grid-line"/><polyline :points="chartPoints" class="trend-area"/><polyline :points="chartPoints" class="trend-line"/><g v-for="dot in chartDots" :key="dot.date"><circle :cx="dot.x" :cy="dot.y" r="5"/><text :x="dot.x" :y="dot.y-12">{{dot.count}}</text></g></svg><div class="trend-labels"><span v-for="item in data.trend" :key="item.date">{{item.label}}</span></div></div></section>
    <section class="data-panel"><div class="panel-title"><div><h2>预约状态分布</h2><p>当前跟进进度</p></div></div><div class="distribution"><div v-for="item in data.statuses" :key="item.status"><div><span>{{item.label}}</span><b>{{item.count}}</b></div><el-progress :percentage="Math.round(item.count/statusMax*100)" :show-text="false" :stroke-width="8"/></div></div></section>
  </div>
  <div class="dashboard-grid bottom-data">
    <section class="data-panel"><div class="panel-title"><div><h2>预约城市排行</h2><p>客户来源最多的城市</p></div></div><div v-if="data.cities.length" class="city-ranking"><div v-for="(item,index) in data.cities" :key="item.city"><i>{{index+1}}</i><span>{{item.city}}</span><div><em :style="{width:`${item.count/cityMax*100}%`}"/></div><b>{{item.count}}</b></div></div><el-empty v-else description="暂无城市数据" :image-size="70"/></section>
    <section class="data-panel recent-panel"><div class="panel-title"><div><h2>最新待联系客户</h2><p>优先处理最新预约</p></div><RouterLink to="/bookings?status=NEW">查看全部 →</RouterLink></div><div v-if="data.recent.length" class="recent-list"><RouterLink v-for="item in data.recent" :key="item.id" :to="`/bookings?keyword=${encodeURIComponent(item.phone)}`"><el-badge :is-dot="item.unread"><span class="avatar">{{item.name.slice(0,1)}}</span></el-badge><div><b>{{item.name}}</b><small>{{item.phone}} · {{item.city||'未填写'}} {{item.district||''}}</small></div><time>{{formatDate(item.createdAt)}}</time></RouterLink></div><el-empty v-else description="暂无待联系预约" :image-size="70"/></section>
  </div>
  <section class="content-overview"><h2>内容数据</h2><div><RouterLink to="/products"><span>车型</span><strong>{{data.stats.products}}</strong></RouterLink><RouterLink to="/news"><span>新闻</span><strong>{{data.stats.news}}</strong></RouterLink><RouterLink to="/slides"><span>轮播图</span><strong>{{data.stats.slides}}</strong></RouterLink></div></section>
</div></template>
<style scoped>
