space-between;margin-bottom:7px;font-size:13px}.distribution b{color:#343a43}.city-ranking{display:grid;gap:17px}.city-ranking>div{display:grid;grid-template-columns:25px 95px 1fr 30px;align-items:center;gap:10px}.city-ranking i{display:grid;place-items:center;width:22px;height:22px;border-radius:7px;background:#eef5ff;color:#0878ee;font-style:normal;font-size:11px;font-weight:800}.city-ranking span{font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.city-ranking>div>div{height:7px;background:#edf0f4;border-radius:5px;overflow:hidden}.city-ranking em{display:block;height:100%;background:linear-gradient(90deg,#0878ee,#55adff);border-radius:5px}.city-ranking b{text-align:right}.recent-list{display:grid}.recent-list>a{display:grid;grid-template-columns:40px 1fr auto;align-items:center;gap:12px;padding:12px 0;color:#1e232a;border-bottom:1px solid #f0f1f3}.recent-list>a:last-child{border:0}.avatar{display:grid;place-items:center;width:36px;height:36px;border-radius:11px;background:#eaf3ff;color:#0878ee;font-weight:800}.recent-list div b,.recent-list div small{display:block}.recent-list div small{color:#8b929a;font-size:11px;margin-top:5px}.recent-list time{color:#9299a2;font-size:11px}.content-overview{background:#fff;border:1px solid #edf0f4;border-radius:14px;padding:20px 24px}.content-overview>div{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.content-overview a{display:flex;align-items:center;justify-content:space-between;background:#f6f8fb;border-radius:10px;padding:15px 18px;color:#444b55}.content-overview strong{font-size:22px;color:#0878ee}@media(max-width:1100px){.kpi-grid{grid-template-columns:repeat(2,1fr)}.main-charts,.bottom-data{grid-template-columns:1fr}}@media(max-width:700px){.kpi-grid{grid-template-columns:1fr}.content-overview>div{grid-template-columns:1fr}}
</style>
